2574 void
2575 ReassociatePass::BuildPairMap(ReversePostOrderTraversal<Function *> &RPOT) {
2576   // Make a "pairmap" of how often each operand pair occurs.
2577   for (BasicBlock *BI : RPOT) {
2578     for (Instruction &I : *BI) {
2579       if (!I.isAssociative() || !I.isBinaryOp())
2580         continue;
2581 
2582       // Ignore nodes that aren't at the root of trees.
2583       if (I.hasOneUse() && I.user_back()->getOpcode() == I.getOpcode())
2584         continue;
2585 
2586       // Collect all operands in a single reassociable expression.
2587       // Since Reassociate has already been run once, we can assume things
2588       // are already canonical according to Reassociation's regime.
2589       SmallVector<Value *, 8> Worklist = { I.getOperand(0), I.getOperand(1) };
2590       SmallVector<Value *, 8> Ops;
2591       while (!Worklist.empty() && Ops.size() <= GlobalReassociateLimit) {
2592         Value *Op = Worklist.pop_back_val();
2593         Instruction *OpI = dyn_cast<Instruction>(Op);
2594         if (!OpI || OpI->getOpcode() != I.getOpcode() || !OpI->hasOneUse()) {
2595           Ops.push_back(Op);
2596           continue;
2597         }
2598         // Be paranoid about self-referencing expressions in unreachable code.
2599         if (OpI->getOperand(0) != OpI)
2600           Worklist.push_back(OpI->getOperand(0));
2601         if (OpI->getOperand(1) != OpI)
2602           Worklist.push_back(OpI->getOperand(1));
2603       }
2604       // Skip extremely long expressions.
2605       if (Ops.size() > GlobalReassociateLimit)
2606         continue;
2607 
2608       // Add all pairwise combinations of operands to the pair map.
2609       unsigned BinaryIdx = I.getOpcode() - Instruction::BinaryOpsBegin;
2610       SmallSet<std::pair<Value *, Value*>, 32> Visited;
2611       for (unsigned i = 0; i < Ops.size() - 1; ++i) {
2612         for (unsigned j = i + 1; j < Ops.size(); ++j) {
2613           // Canonicalize operand orderings.
2614           Value *Op0 = Ops[i];
2615           Value *Op1 = Ops[j];
2616           if (std::less<Value *>()(Op1, Op0))
2617             std::swap(Op0, Op1);
2618           if (!Visited.insert({Op0, Op1}).second)
2619             continue;
2620           auto res = PairMap[BinaryIdx].insert({{Op0, Op1}, {Op0, Op1, 1}});
2621           if (!res.second) {
2622             // If either key value has been erased then we've got the same
2623             // address by coincidence. That can't happen here because nothing is
2624             // erasing values but it can happen by the time we're querying the
2625             // map.
2626             assert(res.first->second.isValid() && "WeakVH invalidated");
2627             ++res.first->second.Score;
2628           }
2629         }
2630       }
2631     }
2632   }
2633 }
